<template>
  <div class="card">
    <div style="height: 180px;">
      <img class="card-img-top" :src="portfolio.picture" alt="Screenshot of project" />
    </div>
    <div class="px-2 title2">{{ portfolio.name }}</div>
    <div class="px-2 date">{{ portfolio.date }}</div>

    
    <p class="title3 m-0 pb-2 pheight pt-1" v-html="portfolio.description.length > 550
                            ? portfolio.description.substring(0, 555) + '...'
                            : portfolio.description
                        ">
                    </p>

    <span class="mx-2 badge p-2 mb-2" v-for="s in portfolio.skills" :key="s">{{ s }}</span>

    <div class="button-container">
      <button class="btn-sm btn btn-outline-secondary no-outline" @click="showModal">
        Read More
      </button>

      <button v-if="portfolio.github" class="btn btn-outline-secondary" @click="open('github')">
        GitHub
        <i class="fa-brands fa-github"></i>
      </button>

      <button v-if="portfolio.youtube" class="btn btn-outline-secondary" @click="open('youtube')">
        Demo Video
        <i class="fa-brands fa-youtube"></i>
      </button>

      <button v-if="portfolio.demo" @click="navigateToDemo" class="btn btn-outline-secondary">
        Test
        <i class="fa-solid fa-laptop-code"></i>
      </button>

      <button v-if="portfolio.contact" @click="open('contact')" class="btn btn-outline-secondary">
        Contact for Code
        <i class="fa-regular fa-envelope"></i>
      </button>
    </div>
  </div>
</template>

<script>
export default {
  name: "CardItem",
  props: {
    portfolio: {
      type: Object,
      required: true,
    },
  },
  methods: {
    open(platform) {
      let url = "";
      switch (platform) {
        case "github":
          url = this.portfolio.github;
          break;
        case "youtube":
          url = this.portfolio.youtube;
          break;
        case "demo":
          url = this.portfolio.demo;
          break;
        case "contact": {
          const email = this.portfolio.contact;
          url = `mailto:${email}`;
          break;
        }
      }

      window.open(url, "_blank");
    },
    navigateToDemo() {
      this.$router.push(this.portfolio.demo);
    },
    showModal() {
      this.$emit("show", this.portfolio); // emit the portfolio object directly
    },
  },
};
</script>

