<template>
  <div class="py-4 p-st" :class="{
    'bg-light': !nightMode,
    'bg-dark2': nightMode,
    'text-light': nightMode,
  }">
    <div class="container">
      <div class="section-container">
        <span class="title text-center">Programming Portfolio</span>
        <hr />
        <div class="row-container">
          <CardItem v-for="portfolio in portfoliosToShow" :key="portfolio.name" :portfolio="portfolio"
            @show="openModal" />
        </div>
      </div>

      <!-- SHOW MORE BUTTON -->
      <div class="text-center py-3" v-if="allPortfolios.length > initialNumberToShow">
        <button class="btn" @click.prevent="showMore">{{ showBtn }}</button>
      </div>
    </div>

    <!-- MODAL -->
     <!-- MODAL -->
<teleport to="body">
  <div v-if="showDesignModal && design_modal_info" class="modal-mask" @click.self="closeModal">
    <div class="modal-wrapper">
      <div class="modal-container" :class="{
        'bg-light': !nightMode,
        'bg-dark': nightMode,
        'text-light': nightMode,
      }">
        <!-- Title with close button pinned to top-right -->
        <div class="modal-header px-4 pt-3">
          <span class="modal-title">{{ design_modal_info.name }}</span>
          <button class="modal-close-btn" @click="closeModal">
            <i class="fas fa-times"></i>
          </button>
        </div>
        <hr class="modal-hr" />

        <div class="modal-body px-4">
          <div class="mb-2 date">{{ design_modal_info.date }}</div>

          <div class="pb-2">
            <span
              class="badge mr-2 mb-2"
              v-for="tech in design_modal_info.skills || []"
              :key="tech"
              :class="{ 'bg-dark4': nightMode }"
            >
              {{ tech }}
            </span>
          </div>

          <div style="text-align: justify">{{ design_modal_info.description }}</div>

          <!-- Gallery -->
          <div class="modal-pictures mt-3">
            <GalleryItem :images="design_modal_info.pictures" :design="true" />
          </div>
        </div>

        <div class="text-center pb-3">
          <hr />
          <button class="btn w-25" @click="closeModal">Close</button>
        </div>
      </div>
    </div>
  </div>
</teleport>


    
  </div>
</template>

<script>
import CardItem from "./helpers/Card";
import GalleryItem from "./helpers/Gallery";
import info from "../../info";

export default {
  name: "PortfolioSection",
  components: { 
    CardItem,
    GalleryItem

  },
  data() {
    return {
      allPortfolios: info.portfolio,
      initialNumberToShow: 5,
      numberToShow: 5,
      showBtn: "Show More",
      showDesignModal: false,
      design_modal_info: null,
    };
  },
  computed: {
    portfoliosToShow() {
      return this.allPortfolios.slice(0, this.numberToShow);
    },
  },
  methods: {
    openModal(portfolio) {
      this.design_modal_info = portfolio;
      this.showDesignModal = true;
      document.body.classList.add("modal-open");
    },
    closeModal() {
      this.showDesignModal = false;
      this.design_modal_info = null;
      document.body.classList.remove("modal-open");
    },
    showMore() {
      if (this.numberToShow < this.allPortfolios.length) {
        this.numberToShow += 3;
        if (this.numberToShow >= this.allPortfolios.length) {
          this.numberToShow = this.allPortfolios.length;
          this.showBtn = "Show Less";
        }
      } else {
        this.numberToShow = this.initialNumberToShow;
        this.showBtn = "Show More";
        window.scrollTo({ top: 0, behavior: "smooth" });
      }
    },
  },
};
</script>

